import{_ as a,o as i,c as l,a0 as o}from"./chunks/framework.DgPozsi0.js";const p=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/04/reactDev_04_04.md","filePath":"pages/f2e/docReact/reactDev/04/reactDev_04_04.md"}'),s={name:"pages/f2e/docReact/reactDev/04/reactDev_04_04.md"};function t(c,e,r,d,n,h){return i(),l("div",null,[...e[0]||(e[0]=[o(`<h1 id="調適和故障排除" tabindex="-1">調適和故障排除 <a class="header-anchor" href="#調適和故障排除" aria-label="Permalink to &quot;調適和故障排除&quot;">​</a></h1><p>本指南可幫助你在使用 React 編譯器（<code>React Compiler</code>）時識別和修復問題。學習如何調試編譯問題並解決常見錯誤。</p><div class="info custom-block"><p class="custom-block-title">你將學到</p><ul><li>編譯器錯誤與運行時問題的區別</li><li>導致編譯失敗的常見模式</li><li>分步調試工作流程</li></ul></div><h2 id="了解編譯器行為" tabindex="-1">了解編譯器行為 <a class="header-anchor" href="#了解編譯器行為" aria-label="Permalink to &quot;了解編譯器行為&quot;">​</a></h2><p>React 編譯器旨在處理遵循 <a href="https://zh-hans.react.dev/reference/rules" target="_blank" rel="noreferrer">React 規則</a> 的代碼。當遇到可能違反這些規則的代碼時，它會安全地跳過優化，而不是冒險改變應用程式的行為。</p><ul><li><h3 id="編譯器錯誤與運行時問題" tabindex="-1">編譯器錯誤與運行時問題 <a class="header-anchor" href="#編譯器錯誤與運行時問題" aria-label="Permalink to &quot;編譯器錯誤與運行時問題&quot;">​</a></h3><ul><li><h4 id="編譯錯誤" tabindex="-1">編譯錯誤 <a class="header-anchor" href="#編譯錯誤" aria-label="Permalink to &quot;編譯錯誤&quot;">​</a></h4><p>發生在建構時，並會阻止你的代碼編譯。這類錯誤很少見，因為編譯器的設計理念是跳過有問題的代碼，而不是直接失敗。</p></li><li><h4 id="運行時問題" tabindex="-1">運行時問題 <a class="header-anchor" href="#運行時問題" aria-label="Permalink to &quot;運行時問題&quot;">​</a></h4><p>發生在已編譯的代碼行為與預期不符時。如果你遇到了與 <code>React</code> 編譯器相關的問題，通常是運行時問題。這往往是因為你的代碼以編譯器無法檢測到的方式輕微違反了 React 的規則，導致編譯器錯誤地編譯了一個本應跳過的組件。</p></li><li><h4 id="調試核心思維" tabindex="-1">調試核心思維 <a class="header-anchor" href="#調試核心思維" aria-label="Permalink to &quot;調試核心思維&quot;">​</a></h4><p>在調試運行時問題時，應集中精力在受影響的組件中查找 <code>ESLint</code> 規則未能檢測到的 <code>React</code> 規則違規情況。</p></li></ul></li></ul><h2 id="常見的破壞性模式" tabindex="-1">常見的破壞性模式 <a class="header-anchor" href="#常見的破壞性模式" aria-label="Permalink to &quot;常見的破壞性模式&quot;">​</a></h2><p><code>React Compiler</code> 可能導致你的應用出錯的一個主要方式是：如果你的代碼是基於「<code>正確性</code>」而非單純的「<code>效能優化</code>」來編寫手動記憶化（<code>memoization</code>）。這意味著你的應用依賴於某些特定值的記憶化才能正常運作。</p><p>由於編譯器的記憶化方式可能與你手動實現的方式不同，這可能導致一些意外行為（例如副作用重複觸發、無限迴圈或更新遺失）。常見場景包括：</p><ul><li><code>依賴引用相等性的副作用</code>：當副作用依賴於對象或陣列在多次渲染中保持相同的引用。</li><li><code>需要穩定引用的依賴陣列</code>：當不穩定的依賴導致副作用觸發過於頻繁或產生無限迴圈。</li><li><code>基於引用判斷的條件邏輯</code>：當代碼使用引用相等性檢查來進行快取或優化。</li></ul><h2 id="調試工作流程" tabindex="-1">調試工作流程 <a class="header-anchor" href="#調試工作流程" aria-label="Permalink to &quot;調試工作流程&quot;">​</a></h2><ul><li><h3 id="遇到編譯器建構錯誤-build-errors" tabindex="-1">遇到編譯器建構錯誤（Build Errors） <a class="header-anchor" href="#遇到編譯器建構錯誤-build-errors" aria-label="Permalink to &quot;遇到編譯器建構錯誤（Build Errors）&quot;">​</a></h3><p>如果你遇到一個意外中斷建構的編譯器錯誤，這很可能是編譯器中的一個 <code>bug</code>。請將以下信息報告到 <a href="https://github.com/facebook/react/issues" target="_blank" rel="noreferrer">facebook/react</a> 倉庫：</p><ul><li>錯誤信息</li><li>導致錯誤的源代碼</li><li>你使用的 React 和編譯器版本</li></ul></li><li><h3 id="遇到運行時問題-runtime-issues" tabindex="-1">遇到運行時問題（Runtime Issues） <a class="header-anchor" href="#遇到運行時問題-runtime-issues" aria-label="Permalink to &quot;遇到運行時問題（Runtime Issues）&quot;">​</a></h3><p>關於運行時行為問題，請依序執行以下分步工作流程：</p></li><li><h3 id="_1-臨時禁用編譯" tabindex="-1">1. 臨時禁用編譯 <a class="header-anchor" href="#_1-臨時禁用編譯" aria-label="Permalink to &quot;1. 臨時禁用編譯&quot;">​</a></h3><p>使用 <code>&quot;use no memo&quot;</code> 指令來確定問題是否與編譯器相關：</p><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ProblematicComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;use no memo&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 跳過該組件的編譯優化</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ... 其餘的組件代碼</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li><code>測試判斷 A</code>：如果加上指令後問題消失，則很可能與違反 <code>React 規則</code> 有關。</li><li><code>測試判斷 B</code>：你還可以嘗試從問題組件中移除所有手動的 <code>memoization</code>（<code>useMemo</code>、<code>useCallback</code> 和 <code>memo</code>），以驗證在沒有任何快取的狀況下應用程式是否能正常工作。如果移除後問題仍然存在，則說明該組件存在必須修復的 React 規則違反情況。</li></ul></li><li><h3 id="_2-逐步修復問題" tabindex="-1">2. 逐步修復問題 <a class="header-anchor" href="#_2-逐步修復問題" aria-label="Permalink to &quot;2. 逐步修復問題&quot;">​</a></h3><ul><li>識別根本原因（通常是上述為了「正確性」而寫的記憶化問題）。</li><li>每次修復後進行測試。</li><li>修復完成並確認正常後，移除 <code>&quot;use no memo&quot;</code> 指令。</li><li>在 <code>React DevTools</code> 中驗證組件是否重新顯示 <code>✨</code> 徽章。</li></ul></li></ul><h2 id="報告編譯器錯誤" tabindex="-1">報告編譯器錯誤 <a class="header-anchor" href="#報告編譯器錯誤" aria-label="Permalink to &quot;報告編譯器錯誤&quot;">​</a></h2><p>如果你認為發現了一個編譯器本身的 <code>bug</code>，請依序確認並提交：</p><ul><li><code>確認不是違反 React 規則的問題</code> - 先使用 ESLint 進行完整檢查。</li><li><code>創建最小的複現代碼</code> - 在一個乾淨的小示例中隔離該問題。</li><li><code>在不使用編譯器的情況下測試</code> - 確認該問題僅在開啟編譯器時才會出現。</li><li><code>提交一個 GitHub Issue</code>，並包含： <ul><li>React 和編譯器的具體版本。</li><li>最小複現代碼（Minimal Reproducible Example）。</li><li>預期行為與實際行為的差異對比。</li><li>任何相關的錯誤日誌或信息。</li></ul></li></ul>`,15)])])}const m=a(s,[["render",t]]);export{p as __pageData,m as default};
